"""Payment Strategy — the service depends on this interface, not a vendor.

🎙️ "The BookingService depends on a PaymentGateway interface, so I can swap
     providers and inject deterministic fakes in tests."
"""
from __future__ import annotations

from abc import ABC, abstractmethod
from typing import Iterable, List

from models import PaymentStatus


class PaymentGateway(ABC):
    # ── WHY THIS CLASS ──────────────────────────────────────────────────────
    # The seam (Dependency Inversion): core logic talks to this abstraction.
    @abstractmethod
    def charge(self, session_id: str, amount: int) -> PaymentStatus:
        ...


class AlwaysSuccessGateway(PaymentGateway):
    def charge(self, session_id: str, amount: int) -> PaymentStatus:
        return PaymentStatus.SUCCESS


class AlwaysFailGateway(PaymentGateway):
    def charge(self, session_id: str, amount: int) -> PaymentStatus:
        return PaymentStatus.FAILURE


class ScriptedGateway(PaymentGateway):
    # ── WHY THIS CLASS ──────────────────────────────────────────────────────
    # Returns results from a list in order so I can test "fail first, then
    # succeed". The last result repeats once the script runs out.
    def __init__(self, results: Iterable[PaymentStatus]) -> None:
        self._results: List[PaymentStatus] = list(results)

    def charge(self, session_id: str, amount: int) -> PaymentStatus:
        if len(self._results) > 1:
            return self._results.pop(0)
        return self._results[0]
